import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.android_studio
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class IndentationRuleRegressionOrOperatorTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given multiline if condition with || at beginning of line then formatting should not crash`() {
        val code =
            """
            fun foo(node: String) {
                if (node.contains("this")
                    || node.contains("that")
                ) {
                    println(node)
                }
            }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to android_studio)
            .hasNoLintViolations()
    }
}
"}

